import java.util.ArrayList;
import java.util.List;

import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

import sailpoint.api.IdentityService;
import sailpoint.api.SailPointContext;
import sailpoint.object.Application;
import sailpoint.object.Custom;
import sailpoint.object.Identity;
import sailpoint.object.Bundle;
import sailpoint.object.Link;
import sailpoint.object.TaskResult;
import sailpoint.object.TaskResult.CompletionStatus;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Message;
import sailpoint.tools.Util;


String KEY_TASK_NAME = "RCA-CorrelateUsers";
String KEY_UNCORRELATED_RCA_ACCOUNTS = "Ascension-Custom-RCA-CorrelateUsers";
String KEY_UNCORRELATED_TAG = "uncorrelatedUsers";
String KEY_APPLICATION_NAME = "AD-DS";
Log logger = LogFactory.getLog("sailpoint.ascension.rca.task.CorrelatedUserWithManager");

private void updateManager(Identity user, Identity managerIdentity, List managerUpdatedList, List rcaUserWithManagerList) throws GeneralException
{
  if (user.getManager() != null)
  {
	 rcaUserWithManagerList.add(user.getName());
	 return;
  }
  user.setManager(managerIdentity);
  context.saveObject(user);
  managerUpdatedList.add("IdentityName: " + user.getName());

}
private boolean hasRCARoles(Identity correlatedIdentity)
{
  List detectedRoles = correlatedIdentity.getDetectedRoles();
  for (Bundle role : detectedRoles)
  {
	 if (role.getName().contains("-AttestRCA"))
		return true;
  }
  return false;
}


private Link getRCALink(IdentityService idenService, Identity rcaOrphanIdentity, Application application,
		String rcaUserName, TaskResult taskResult)
{
  try
  {
	 List addsLinks = idenService.getLinks(rcaOrphanIdentity, application);
	 for (Link addsLink : addsLinks)
	 {
		String linkDisplayName = addsLink.getDisplayName();
		if (Util.isNotNullOrEmpty(linkDisplayName) && linkDisplayName.contains("\\" + rcaUserName))
		{
		   return addsLink;
		}
	 }
  }
  catch (GeneralException e)
  {
	 taskResult.addMessage(Message.error(null, e.getLocalizedMessage()));
	 logger.error("RCA || Exception = " + e.getStackTrace());
	 taskResult.setCompletionStatus(CompletionStatus.Warning);
  }
  return null;
}


public String correlateUsers() throws GeneralException
{
  List incorrectUserDataList = new ArrayList();
  List managersNotFound = new ArrayList();
  List rcaUserWithManagerList = new ArrayList();
  List accountsNotFoundInSailPoint = new ArrayList();
  List managerUpdatedList = new ArrayList();
  Application application = context.getObject(Application.class, KEY_APPLICATION_NAME);

  TaskResult taskResult = context.getObjectByName(TaskResult.class, KEY_TASK_NAME);
  Custom customObj = context.getObjectByName(Custom.class, KEY_UNCORRELATED_RCA_ACCOUNTS);
  if (customObj == null)
	 throw new RuntimeException(
			  "RCA || Custom object does not exists! Custom obj: " + KEY_UNCORRELATED_RCA_ACCOUNTS);
  List uncorrelatedUsers = customObj.getList(KEY_UNCORRELATED_TAG);
  if (uncorrelatedUsers == null || uncorrelatedUsers.isEmpty())
	 throw new RuntimeException("RCA || no uncorrelated users found");

  IdentityService idenService = new IdentityService(context);
  for (String userDataInCsv : uncorrelatedUsers)
  {
	 String rcaUserName = null;
	 String employeeId = null;
	 String managerEmpID = null;
	 List singleUserData = Util.csvToList(userDataInCsv);
	 if (singleUserData.size() == 3)
	 {
		rcaUserName = singleUserData.get(0);
		employeeId = singleUserData.get(1);
		managerEmpID = singleUserData.get(2);
	 }
	 else
	 {
		incorrectUserDataList.add(userDataInCsv + " | ");
		continue;
	 }

	 Identity rcaOrphanIdentity = context.getObject(Identity.class, rcaUserName);
	 Identity correlatedIdentity = context.getObject(Identity.class, employeeId);
	 Identity managerIdentity = context.getObject(Identity.class, managerEmpID);

	 if (managerIdentity == null)
	 {
		managersNotFound.add(managerEmpID);
		continue;
	 }
	 if (correlatedIdentity == null && rcaOrphanIdentity == null)
	 {
		accountsNotFoundInSailPoint.add("EmployeeID: " + employeeId + " | RCA_UserName: " + rcaUserName);
		continue;
	 }
	 else if (correlatedIdentity == null && rcaOrphanIdentity != null)
	 {
		if (hasRCARoles(rcaOrphanIdentity))
		   updateManager(rcaOrphanIdentity, managerIdentity, managerUpdatedList, rcaUserWithManagerList);
		else
		{
		   accountsNotFoundInSailPoint.add("EmployeeID: " + employeeId + " | RCA_UserName: " + rcaUserName);
		   continue;
		}
	 }
	 else if (correlatedIdentity != null && rcaOrphanIdentity == null)
	 {
		if (hasRCARoles(correlatedIdentity))
		   updateManager(correlatedIdentity, managerIdentity, managerUpdatedList, rcaUserWithManagerList);
		else
		{
		   accountsNotFoundInSailPoint.add("EmployeeID: " + employeeId + " | RCA_UserName: " + rcaUserName);
		   continue;
		}
	 }
	 else if (correlatedIdentity != null && rcaOrphanIdentity != null)
	 {
		if (hasRCARoles(rcaOrphanIdentity))
			 updateManager(rcaOrphanIdentity, managerIdentity, managerUpdatedList, rcaUserWithManagerList);
		else if(hasRCARoles(correlatedIdentity))
		   updateManager(correlatedIdentity, managerIdentity, managerUpdatedList, rcaUserWithManagerList);
		else
		   accountsNotFoundInSailPoint.add("EmployeeID: " + employeeId + " | RCA_UserName: " + rcaUserName);
	 }
  }

  StringBuilder results = new StringBuilder();
  results.append("incorrectUserDataList: " + incorrectUserDataList + " || ");
  results.append("managersNotFound: " + managersNotFound + " || ");
  results.append("accountsNotFoundInSailPoint: " + accountsNotFoundInSailPoint + " || ");
  results.append("rcaUserWithManagerList: " + rcaUserWithManagerList + " || ");
  results.append("managerUpdatedList: " + managerUpdatedList);

  logger.error("RCA || incorrectUserData from custom object = " + incorrectUserDataList);
  logger.error("RCA || managersNotFound = " + managersNotFound);
  logger.error("RCA || RCA Accounts Not Found In SailPoint = " + accountsNotFoundInSailPoint);
  logger.info("RCA || rcaUserWithManagerList = " + rcaUserWithManagerList);
  logger.info("RCA || managerUpdatedList = " + managerUpdatedList);
  
  taskResult.addMessage(Message.warn("RCA || incorrectUserDataList - " + incorrectUserDataList));
  taskResult.addMessage(Message.warn("RCA || Managers not found - " + managersNotFound));
  taskResult.addMessage(Message.warn("RCA || RCA accounts not found in sailpoint - " + accountsNotFoundInSailPoint));
  taskResult.addMessage(Message.info("RCA || rcaUserWithManagerList - " + rcaUserWithManagerList));
  taskResult.addMessage(Message.info("RCA || managerUpdatedList - " + managerUpdatedList));
  return results.toString();
}
correlateUsers();
